import React, { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { FiShield, FiCheck, FiX, FiRefreshCw } from 'react-icons/fi';
import axios from 'axios';
import toast from 'react-hot-toast';

const AdminPanel = () => {
  const { user: currentUser } = useAuth();
  const [rejectedActivities, setRejectedActivities] = useState([]);
  const [pendingActivities, setPendingActivities] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [selectedActivities, setSelectedActivities] = useState([]);
  const [filter, setFilter] = useState('rejected');

  useEffect(() => {
    loadAdminData();
  }, []);

  const loadAdminData = async () => {
    try {
      setLoading(true);
      
      // Load rejected activities
      const rejectedResponse = await axios.get('/api/v1/admin/rejected');
      setRejectedActivities(rejectedResponse.data);
      
      // Load pending activities
      const pendingResponse = await axios.get('/api/v1/admin/pending');
      setPendingActivities(pendingResponse.data);
      
      // Load stats
      const statsResponse = await axios.get('/api/v1/admin/stats');
      setStats(statsResponse.data);
      
    } catch (error) {
      console.error('Error loading admin data:', error);
      toast.error('Failed to load admin data');
    } finally {
      setLoading(false);
    }
  };

  const approveActivity = async (activityId, comments = '') => {
    try {
      await axios.post(`/api/v1/admin/approve/${activityId}`, { comments });
      toast.success('Activity approved successfully');
      loadAdminData();
    } catch (error) {
      const message = error.response?.data?.detail || 'Failed to approve activity';
      toast.error(message);
    }
  };

  const discardActivity = async (activityId, comments = '') => {
    try {
      await axios.post(`/api/v1/admin/discard/${activityId}`, { comments });
      toast.success('Activity discarded successfully');
      loadAdminData();
    } catch (error) {
      const message = error.response?.data?.detail || 'Failed to discard activity';
      toast.error(message);
    }
  };

  const bulkApprove = async () => {
    if (selectedActivities.length === 0) {
      toast.error('Please select activities to approve');
      return;
    }

    try {
      await axios.post('/api/v1/admin/bulk-approve', {
        activity_ids: selectedActivities
      });
      toast.success(`${selectedActivities.length} activities approved successfully`);
      setSelectedActivities([]);
      loadAdminData();
    } catch (error) {
      const message = error.response?.data?.detail || 'Failed to approve activities';
      toast.error(message);
    }
  };

  const bulkDiscard = async () => {
    if (selectedActivities.length === 0) {
      toast.error('Please select activities to discard');
      return;
    }

    try {
      await axios.post('/api/v1/admin/bulk-discard', {
        activity_ids: selectedActivities
      });
      toast.success(`${selectedActivities.length} activities discarded successfully`);
      setSelectedActivities([]);
      loadAdminData();
    } catch (error) {
      const message = error.response?.data?.detail || 'Failed to discard activities';
      toast.error(message);
    }
  };

  const toggleActivitySelection = (activityId) => {
    setSelectedActivities(prev => 
      prev.includes(activityId) 
        ? prev.filter(id => id !== activityId)
        : [...prev, activityId]
    );
  };

  const selectAllActivities = () => {
    const currentActivities = filter === 'rejected' ? rejectedActivities : pendingActivities;
    setSelectedActivities(currentActivities.map(activity => activity.id));
  };

  const clearSelection = () => {
    setSelectedActivities([]);
  };

  const getStatusColor = (status) => {
    const colors = {
      pending: 'status-pending',
      accepted: 'status-accepted',
      rejected: 'status-rejected'
    };
    return colors[status] || 'status-pending';
  };

  const getTypeColor = (type) => {
    const colors = {
      social: 'type-social',
      sports: 'type-sports',
      academic: 'type-academic',
      cultural: 'type-cultural',
      technical: 'type-technical'
    };
    return colors[type] || 'type-social';
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="spinner"></div>
      </div>
    );
  }

  const currentActivities = filter === 'rejected' ? rejectedActivities : pendingActivities;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 flex items-center">
            <FiShield className="h-8 w-8 mr-3 text-blue-600" />
            Admin Panel
          </h1>
          <p className="mt-2 text-gray-600">
            Review and manage activities submitted by users.
          </p>
        </div>
        <button
          onClick={loadAdminData}
          className="btn-secondary inline-flex items-center"
        >
          <FiRefreshCw className="h-4 w-4 mr-2" />
          Refresh
        </button>
      </div>

      {/* Stats Cards */}
      {stats && (
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
          <div className="card">
            <div className="flex items-center">
              <div className="flex-shrink-0">
                <div className="w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center">
                  <span className="text-blue-600 font-semibold">T</span>
                </div>
              </div>
              <div className="ml-4">
                <p className="text-sm font-medium text-gray-500">Total Activities</p>
                <p className="text-2xl font-semibold text-gray-900">{stats.total_activities}</p>
              </div>
            </div>
          </div>

          <div className="card">
            <div className="flex items-center">
              <div className="flex-shrink-0">
                <div className="w-8 h-8 bg-green-100 rounded-full flex items-center justify-center">
                  <span className="text-green-600 font-semibold">A</span>
                </div>
              </div>
              <div className="ml-4">
                <p className="text-sm font-medium text-gray-500">Accepted</p>
                <p className="text-2xl font-semibold text-gray-900">{stats.accepted_activities}</p>
              </div>
            </div>
          </div>

          <div className="card">
            <div className="flex items-center">
              <div className="flex-shrink-0">
                <div className="w-8 h-8 bg-red-100 rounded-full flex items-center justify-center">
                  <span className="text-red-600 font-semibold">R</span>
                </div>
              </div>
              <div className="ml-4">
                <p className="text-sm font-medium text-gray-500">Rejected</p>
                <p className="text-2xl font-semibold text-gray-900">{stats.rejected_activities}</p>
              </div>
            </div>
          </div>

          <div className="card">
            <div className="flex items-center">
              <div className="flex-shrink-0">
                <div className="w-8 h-8 bg-yellow-100 rounded-full flex items-center justify-center">
                  <span className="text-yellow-600 font-semibold">P</span>
                </div>
              </div>
              <div className="ml-4">
                <p className="text-sm font-medium text-gray-500">Pending</p>
                <p className="text-2xl font-semibold text-gray-900">{stats.pending_activities}</p>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Filter Tabs */}
      <div className="mb-6">
        <div className="border-b border-gray-200">
          <nav className="-mb-px flex space-x-8">
            <button
              onClick={() => setFilter('rejected')}
              className={`py-2 px-1 border-b-2 font-medium text-sm ${
                filter === 'rejected'
                  ? 'border-red-500 text-red-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
              }`}
            >
              Rejected Activities ({rejectedActivities.length})
            </button>
            <button
              onClick={() => setFilter('pending')}
              className={`py-2 px-1 border-b-2 font-medium text-sm ${
                filter === 'pending'
                  ? 'border-yellow-500 text-yellow-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
              }`}
            >
              Pending Activities ({pendingActivities.length})
            </button>
          </nav>
        </div>
      </div>

      {/* Bulk Actions */}
      {currentActivities.length > 0 && (
        <div className="card mb-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-4">
              <button
                onClick={selectAllActivities}
                className="text-sm text-blue-600 hover:text-blue-700"
              >
                Select All
              </button>
              <button
                onClick={clearSelection}
                className="text-sm text-gray-600 hover:text-gray-700"
              >
                Clear Selection
              </button>
              <span className="text-sm text-gray-500">
                {selectedActivities.length} selected
              </span>
            </div>
            <div className="flex items-center space-x-2">
              <button
                onClick={bulkApprove}
                disabled={selectedActivities.length === 0}
                className="btn-success text-sm disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <FiCheck className="h-4 w-4 mr-1" />
                Approve Selected
              </button>
              <button
                onClick={bulkDiscard}
                disabled={selectedActivities.length === 0}
                className="btn-danger text-sm disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <FiX className="h-4 w-4 mr-1" />
                Discard Selected
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Activities List */}
      <div className="card">
        {currentActivities.length > 0 ? (
          <div className="space-y-4">
            {currentActivities.map((activity) => (
              <div key={activity.id} className="border border-gray-200 rounded-lg p-6">
                <div className="flex items-start space-x-4">
                  <input
                    type="checkbox"
                    checked={selectedActivities.includes(activity.id)}
                    onChange={() => toggleActivitySelection(activity.id)}
                    className="mt-1 h-4 w-4 text-blue-600 focus:ring-blue-500 border-gray-300 rounded"
                  />
                  
                  <div className="flex-1">
                    <div className="flex items-center space-x-4 mb-2">
                      <h3 className="text-lg font-medium text-gray-900">{activity.title}</h3>
                      <span className={`status-badge ${getStatusColor(activity.status)}`}>
                        {activity.status}
                      </span>
                      <span className={`type-badge ${getTypeColor(activity.type)}`}>
                        {activity.type}
                      </span>
                    </div>
                    
                    <p className="text-gray-600 mb-4">{activity.description}</p>
                    
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
                      <div>
                        <span className="text-sm font-medium text-gray-500">Department:</span>
                        <span className="ml-2 text-sm text-gray-900">{activity.department}</span>
                      </div>
                      <div>
                        <span className="text-sm font-medium text-gray-500">Year:</span>
                        <span className="ml-2 text-sm text-gray-900">{activity.year}</span>
                      </div>
                      <div>
                        <span className="text-sm font-medium text-gray-500">Images:</span>
                        <span className="ml-2 text-sm text-gray-900">{activity.images?.length || 0}</span>
                      </div>
                    </div>
                    
                    {activity.images && activity.images.length > 0 && (
                      <div className="mb-4">
                        <h4 className="text-sm font-medium text-gray-900 mb-2">ML Verification Results:</h4>
                        <div className="space-y-2">
                          {activity.images.map((image, index) => (
                            <div key={index} className="flex items-center space-x-2 text-sm">
                              <span className="text-gray-600">{image.filename}</span>
                              <span className={`px-2 py-1 rounded-full text-xs ${
                                image.verdict === 'normal' 
                                  ? 'bg-green-100 text-green-800' 
                                  : 'bg-red-100 text-red-800'
                              }`}>
                                {image.verdict} ({image.score.toFixed(2)})
                              </span>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}
                    
                    {activity.admin_comments && (
                      <div className="p-3 bg-yellow-50 border border-yellow-200 rounded-md mb-4">
                        <p className="text-sm text-yellow-800">
                          <strong>Admin Comments:</strong> {activity.admin_comments}
                        </p>
                      </div>
                    )}
                  </div>
                  
                  <div className="flex items-center space-x-2">
                    <button
                      onClick={() => approveActivity(activity.id)}
                      className="btn-success text-sm"
                    >
                      <FiCheck className="h-4 w-4 mr-1" />
                      Approve
                    </button>
                    <button
                      onClick={() => discardActivity(activity.id)}
                      className="btn-danger text-sm"
                    >
                      <FiX className="h-4 w-4 mr-1" />
                      Discard
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-12">
            <FiShield className="mx-auto h-12 w-12 text-gray-400" />
            <h3 className="mt-2 text-sm font-medium text-gray-900">
              No {filter} activities
            </h3>
            <p className="mt-1 text-sm text-gray-500">
              All activities have been reviewed.
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;
