import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { FiArrowLeft, FiCalendar, FiUser, FiTag, FiImage, FiCheckCircle, FiXCircle, FiClock } from 'react-icons/fi';
import { useAuth } from '../contexts/AuthContext';
import { toast } from 'react-hot-toast';

const ActivityDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [activity, setActivity] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchActivity = async () => {
      try {
        const response = await fetch(`/api/activities/${id}`, {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('token')}`,
          },
        });

        if (response.ok) {
          const data = await response.json();
          setActivity(data);
        } else {
          toast.error('Failed to fetch activity details');
          navigate('/activities');
        }
      } catch (error) {
        console.error('Error fetching activity:', error);
        toast.error('Error fetching activity details');
        navigate('/activities');
      } finally {
        setLoading(false);
      }
    };

    if (id) {
      fetchActivity();
    }
  }, [id, navigate]);

  const getStatusColor = (status) => {
    switch (status) {
      case 'approved':
        return 'text-green-600 bg-green-100';
      case 'rejected':
        return 'text-red-600 bg-red-100';
      case 'pending':
        return 'text-yellow-600 bg-yellow-100';
      default:
        return 'text-gray-600 bg-gray-100';
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'approved':
        return <FiCheckCircle className="w-4 h-4" />;
      case 'rejected':
        return <FiXCircle className="w-4 h-4" />;
      case 'pending':
        return <FiClock className="w-4 h-4" />;
      default:
        return <FiClock className="w-4 h-4" />;
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-32 w-32 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  if (!activity) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-2xl font-bold text-gray-900 mb-4">Activity Not Found</h2>
          <p className="text-gray-600 mb-6">The activity you're looking for doesn't exist.</p>
          <button
            onClick={() => navigate('/activities')}
            className="bg-primary-600 text-white px-4 py-2 rounded-lg hover:bg-primary-700 transition-colors"
          >
            Back to Activities
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="mb-8">
          <button
            onClick={() => navigate('/activities')}
            className="flex items-center text-gray-600 hover:text-gray-900 mb-4 transition-colors"
          >
            <FiArrowLeft className="w-4 h-4 mr-2" />
            Back to Activities
          </button>
          
          <div className="flex items-center justify-between">
            <h1 className="text-3xl font-bold text-gray-900">{activity.title}</h1>
            <div className={`flex items-center px-3 py-1 rounded-full text-sm font-medium ${getStatusColor(activity.status)}`}>
              {getStatusIcon(activity.status)}
              <span className="ml-2 capitalize">{activity.status}</span>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Main Content */}
          <div className="lg:col-span-2">
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 mb-6">
              <h2 className="text-xl font-semibold text-gray-900 mb-4">Description</h2>
              <p className="text-gray-700 leading-relaxed">{activity.description}</p>
            </div>

            {/* Images */}
            {activity.images && activity.images.length > 0 && (
              <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 mb-6">
                <h2 className="text-xl font-semibold text-gray-900 mb-4 flex items-center">
                  <FiImage className="w-5 h-5 mr-2" />
                  Images
                </h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {activity.images.map((image, index) => (
                    <div key={index} className="relative">
                      <img
                        src={image.url}
                        alt={`Activity image ${index + 1}`}
                        className="w-full h-48 object-cover rounded-lg"
                      />
                      {image.ml_verified !== undefined && (
                        <div className={`absolute top-2 right-2 px-2 py-1 rounded text-xs font-medium ${
                          image.ml_verified ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                        }`}>
                          {image.ml_verified ? 'Verified' : 'Rejected'}
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* ML Analysis */}
            {activity.ml_analysis && (
              <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
                <h2 className="text-xl font-semibold text-gray-900 mb-4">ML Analysis</h2>
                <div className="space-y-3">
                  <div className="flex justify-between">
                    <span className="text-gray-600">Confidence Score:</span>
                    <span className="font-medium">{Math.round(activity.ml_analysis.confidence * 100)}%</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-600">Prediction:</span>
                    <span className="font-medium capitalize">{activity.ml_analysis.prediction}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-600">Verified:</span>
                    <span className={`font-medium ${activity.ml_analysis.verified ? 'text-green-600' : 'text-red-600'}`}>
                      {activity.ml_analysis.verified ? 'Yes' : 'No'}
                    </span>
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Sidebar */}
          <div className="space-y-6">
            {/* Activity Info */}
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Activity Details</h3>
              <div className="space-y-4">
                <div className="flex items-center text-gray-600">
                  <FiCalendar className="w-4 h-4 mr-3" />
                  <span className="text-sm">
                    {new Date(activity.date).toLocaleDateString()}
                  </span>
                </div>
                
                <div className="flex items-center text-gray-600">
                  <FiUser className="w-4 h-4 mr-3" />
                  <span className="text-sm">{activity.user?.name || 'Unknown User'}</span>
                </div>
                
                <div className="flex items-center text-gray-600">
                  <FiTag className="w-4 h-4 mr-3" />
                  <span className="text-sm capitalize">{activity.category}</span>
                </div>
              </div>
            </div>

            {/* Admin Actions */}
            {user?.role === 'admin' && activity.status === 'pending' && (
              <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
                <h3 className="text-lg font-semibold text-gray-900 mb-4">Admin Actions</h3>
                <div className="space-y-3">
                  <button className="w-full bg-green-600 text-white py-2 px-4 rounded-lg hover:bg-green-700 transition-colors">
                    Approve Activity
                  </button>
                  <button className="w-full bg-red-600 text-white py-2 px-4 rounded-lg hover:bg-red-700 transition-colors">
                    Reject Activity
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ActivityDetail;
