import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { FiPlus, FiEye, FiEdit, FiTrash2, FiSearch } from 'react-icons/fi';
import axios from 'axios';

const Activities = () => {
  const { user: currentUser } = useAuth();
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    type: '',
    status: '',
    year: '',
    search: ''
  });
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);

  useEffect(() => {
    loadActivities();
  }, [currentPage, filters, loadActivities]);

  const loadActivities = async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams({
        page: currentPage,
        size: 10,
        ...filters
      });
      
      const response = await axios.get(`/api/v1/activities?${params}`);
      setActivities(response.data.activities || []);
      setTotalPages(response.data.pages || 1);
    } catch (error) {
      console.error('Error loading activities:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleFilterChange = (e) => {
    setFilters({
      ...filters,
      [e.target.name]: e.target.value
    });
    setCurrentPage(1);
  };

  const handleSearch = (e) => {
    setFilters({
      ...filters,
      search: e.target.value
    });
    setCurrentPage(1);
  };

  const deleteActivity = async (activityId) => {
    if (!window.confirm('Are you sure you want to delete this activity?')) {
      return;
    }

    try {
      await axios.delete(`/api/v1/activities/${activityId}`);
      loadActivities();
    } catch (error) {
      console.error('Error deleting activity:', error);
    }
  };

  const getStatusColor = (status) => {
    const colors = {
      pending: 'status-pending',
      accepted: 'status-accepted',
      rejected: 'status-rejected'
    };
    return colors[status] || 'status-pending';
  };

  const getTypeColor = (type) => {
    const colors = {
      social: 'type-social',
      sports: 'type-sports',
      academic: 'type-academic',
      cultural: 'type-cultural',
      technical: 'type-technical'
    };
    return colors[type] || 'type-social';
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="spinner"></div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Activities</h1>
          <p className="mt-2 text-gray-600">
            Manage your submitted activities and track their status.
          </p>
        </div>
        <Link
          to="/activities/create"
          className="btn-primary inline-flex items-center"
        >
          <FiPlus className="h-4 w-4 mr-2" />
          Create Activity
        </Link>
      </div>

      {/* Filters */}
      <div className="card mb-6">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div>
            <label className="form-label">Search</label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <FiSearch className="h-5 w-5 text-gray-400" />
              </div>
              <input
                type="text"
                className="form-input pl-10"
                placeholder="Search activities..."
                value={filters.search}
                onChange={handleSearch}
              />
            </div>
          </div>
          
          <div>
            <label className="form-label">Type</label>
            <select
              name="type"
              className="form-input"
              value={filters.type}
              onChange={handleFilterChange}
            >
              <option value="">All Types</option>
              <option value="social">Social</option>
              <option value="sports">Sports</option>
              <option value="academic">Academic</option>
              <option value="cultural">Cultural</option>
              <option value="technical">Technical</option>
            </select>
          </div>
          
          <div>
            <label className="form-label">Status</label>
            <select
              name="status"
              className="form-input"
              value={filters.status}
              onChange={handleFilterChange}
            >
              <option value="">All Statuses</option>
              <option value="pending">Pending</option>
              <option value="accepted">Accepted</option>
              <option value="rejected">Rejected</option>
            </select>
          </div>
          
          <div>
            <label className="form-label">Year</label>
            <select
              name="year"
              className="form-input"
              value={filters.year}
              onChange={handleFilterChange}
            >
              <option value="">All Years</option>
              <option value="2024">2024</option>
              <option value="2023">2023</option>
              <option value="2022">2022</option>
            </select>
          </div>
        </div>
      </div>

      {/* Activities List */}
      <div className="card">
        {activities.length > 0 ? (
          <div className="space-y-4">
            {activities.map((activity) => (
              <div key={activity.id} className="border border-gray-200 rounded-lg p-6 hover:shadow-md transition-shadow">
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center space-x-4 mb-2">
                      <h3 className="text-lg font-medium text-gray-900">{activity.title}</h3>
                      <span className={`status-badge ${getStatusColor(activity.status)}`}>
                        {activity.status}
                      </span>
                      <span className={`type-badge ${getTypeColor(activity.type)}`}>
                        {activity.type}
                      </span>
                    </div>
                    
                    <p className="text-gray-600 mb-4">{activity.description}</p>
                    
                    <div className="flex items-center space-x-6 text-sm text-gray-500">
                      <span>Department: {activity.department}</span>
                      <span>Year: {activity.year}</span>
                      <span>Images: {activity.images?.length || 0}</span>
                      <span>Created: {new Date(activity.created_at).toLocaleDateString()}</span>
                    </div>
                    
                    {activity.admin_comments && (
                      <div className="mt-3 p-3 bg-yellow-50 border border-yellow-200 rounded-md">
                        <p className="text-sm text-yellow-800">
                          <strong>Admin Comments:</strong> {activity.admin_comments}
                        </p>
                      </div>
                    )}
                  </div>
                  
                  <div className="flex items-center space-x-2 ml-4">
                    <Link
                      to={`/activities/${activity.id}`}
                      className="p-2 text-gray-400 hover:text-gray-600"
                      title="View Details"
                    >
                      <FiEye className="h-4 w-4" />
                    </Link>
                    
                    {activity.status !== 'accepted' && (
                      <Link
                        to={`/activities/${activity.id}/edit`}
                        className="p-2 text-gray-400 hover:text-gray-600"
                        title="Edit"
                      >
                        <FiEdit className="h-4 w-4" />
                      </Link>
                    )}
                    
                    {activity.status !== 'accepted' && (
                      <button
                        onClick={() => deleteActivity(activity.id)}
                        className="p-2 text-gray-400 hover:text-red-600"
                        title="Delete"
                      >
                        <FiTrash2 className="h-4 w-4" />
                      </button>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-12">
            <FiPlus className="mx-auto h-12 w-12 text-gray-400" />
            <h3 className="mt-2 text-sm font-medium text-gray-900">No activities found</h3>
            <p className="mt-1 text-sm text-gray-500">
              Get started by creating your first activity.
            </p>
            <div className="mt-6">
              <Link
                to="/activities/create"
                className="btn-primary inline-flex items-center"
              >
                <FiPlus className="h-4 w-4 mr-2" />
                Create Activity
              </Link>
            </div>
          </div>
        )}
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex items-center justify-between mt-6">
          <div className="text-sm text-gray-700">
            Page {currentPage} of {totalPages}
          </div>
          <div className="flex space-x-2">
            <button
              onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
              disabled={currentPage === 1}
              className="px-3 py-2 text-sm font-medium text-gray-500 bg-white border border-gray-300 rounded-md hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Previous
            </button>
            <button
              onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
              disabled={currentPage === totalPages}
              className="px-3 py-2 text-sm font-medium text-gray-500 bg-white border border-gray-300 rounded-md hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Next
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Activities;
